+package com.example.cache;
+
+import com.example.auth.Session;
+import org.springframework.data.redis.core.RedisTemplate;
+import org.springframework.stereotype.Component;
+
+import java.time.Duration;
+import java.util.Optional;
+
+@Component
+public class RedisSessionCache {
+
+    private static final String KEY_PREFIX = "session:";
+    private final RedisTemplate<String, Session> redisTemplate;
+    private final Duration ttl;
+
+    public RedisSessionCache(RedisTemplate<String, Session> redisTemplate,
+                              @Value("${session.ttl.minutes:30}") int ttlMinutes) {
+        this.redisTemplate = redisTemplate;
+        this.ttl = Duration.ofMinutes(ttlMinutes);
+    }
+
+    public void put(String sessionId, Session session) {
+        redisTemplate.opsForValue().set(KEY_PREFIX + sessionId, session, ttl);
+    }
+
+    public Optional<Session> get(String sessionId) {
+        return Optional.ofNullable(redisTemplate.opsForValue().get(KEY_PREFIX + sessionId));
+    }
+
+    public void evict(String sessionId) {
+        redisTemplate.delete(KEY_PREFIX + sessionId);
+    }
+}

